import React, { createContext, useContext, useMemo } from 'react';
import { useSearchParams } from 'react-router-dom';

const VALID_TABS = new Set(['actions', 'scoreboard', 'monitor']);

const OptimizationHubCtx = createContext(null);

export function OptimizationHubProvider({ children }) {
  const [searchParams, setSearchParams] = useSearchParams();
  const rawTab = searchParams.get('tab') || 'actions';
  const tab = VALID_TABS.has(rawTab) ? rawTab : 'actions';

  const setTab = (nextTab) => {
    if (!VALID_TABS.has(nextTab)) return;
    setSearchParams({ tab: nextTab }, { replace: true });
  };

  const value = useMemo(() => ({ tab, setTab }), [tab]);

  return (
    <OptimizationHubCtx.Provider value={value}>
      {children}
    </OptimizationHubCtx.Provider>
  );
}

export function useOptimizationHub() {
  const ctx = useContext(OptimizationHubCtx);
  if (!ctx) {
    throw new Error('useOptimizationHub must be used within OptimizationHubProvider');
  }
  return ctx;
}

export const OPTIMIZATION_HUB_TABS = [
  { id: 'actions', label: 'Actions', iconKey: 'actions' },
  { id: 'scoreboard', label: 'Scoreboard', iconKey: 'scoreboard' },
  { id: 'monitor', label: 'Rollout monitor', iconKey: 'rollout' },
];
